//! Define bit-accurate layout of hw trace generated by the Instruction scheduler
//! Rely on bitfield_struct that as a 128b limits
use bitfield_struct::bitfield;

use crate::asm::dop;

// High-level view of the trace.
#[derive(Debug, serde::Serialize, serde::Deserialize)]
pub struct IscTrace {
    pub state: IscPoolState,
    pub insn_hex: u32,
    pub insn_asm: Option<String>,
    pub timestamp: u32,
}

#[derive(Debug, serde::Serialize, serde::Deserialize)]
pub struct IscPoolState {
    pub pdg: bool,
    pub rd_pdg: bool,
    pub vld: bool,
    pub cmd: IscCommand,
    pub wr_lock: u32,
    pub rd_lock: u32,
    pub issue_lock: u32,
    pub sync_id: u32,
}

#[derive(Debug, Clone, Copy, serde::Serialize, serde::Deserialize)]
#[repr(u8)]
pub enum IscCommand {
    None = 0,
    RdUnlock,
    Retire,
    Refill,
    Issue,
}

// Low-level bit representation
#[bitfield(u128)]
pub struct IscTraceFmtFlit1 {
    #[bits(26)]
    _reserved: u32,
    pdg: bool,
    rd_pdg: bool,
    vld: bool,
    #[bits(3)]
    cmd: u8,
    wr_lock: u32,
    rd_lock: u32,
    issue_lock: u32,
}

#[bitfield(u128)]
pub struct IscTraceFmtFlit0 {
    #[bits(32)]
    _reserved: u32,
    sync_id: u32,
    insn: u32,
    timestamp: u32,
}

/// Parsing error
#[derive(thiserror::Error, Debug, Clone)]
pub enum TraceParsingError {
    #[error("Incomplete stream")]
    EmptyStream,
    #[error("Incorrect value {0}")]
    IncorrectValue(String), // TODO extend error handling
}

impl IscTrace {
    pub fn bytes_size() -> usize {
        32
    }
    pub fn bit_size() -> usize {
        256
    }
    pub fn from_bytes(bytes: &[u8]) -> Result<Self, TraceParsingError> {
        let (flit0, flit1) = if bytes.len() != Self::bytes_size() {
            return Err(TraceParsingError::EmptyStream);
        } else {
            let flit0_raw = u128::from_le_bytes(bytes[0..16].try_into().unwrap());
            let flit0 = IscTraceFmtFlit0::from_bits(flit0_raw);
            let flit1_raw = u128::from_le_bytes(bytes[16..32].try_into().unwrap());
            let flit1 = IscTraceFmtFlit1::from_bits(flit1_raw);
            (flit0, flit1)
        };

        let asm = dop::DOp::from_hex(flit0.insn())
            .map_err(|x| TraceParsingError::IncorrectValue(x.to_string()))?
            .to_string();

        Ok(Self {
            state: IscPoolState {
                pdg: flit1.pdg(),
                rd_pdg: flit1.rd_pdg(),
                vld: flit1.vld(),
                cmd: unsafe { std::mem::transmute(flit1.cmd()) },
                wr_lock: flit1.wr_lock(),
                rd_lock: flit1.rd_lock(),
                issue_lock: flit1.issue_lock(),
                sync_id: flit0.sync_id(),
            },
            insn_hex: flit0.insn(),
            insn_asm: Some(asm),
            timestamp: flit0.timestamp(),
        })
    }

    pub fn into_bytes(&self) -> Vec<u8> {
        let flit0 = IscTraceFmtFlit0::new()
            .with_sync_id(self.state.sync_id)
            .with_insn(self.insn_hex)
            .with_timestamp(self.timestamp);
        let flit1 = IscTraceFmtFlit1::new()
            .with_pdg(self.state.pdg)
            .with_rd_pdg(self.state.rd_pdg)
            .with_vld(self.state.vld)
            .with_cmd(self.state.cmd as _)
            .with_wr_lock(self.state.wr_lock)
            .with_rd_lock(self.state.rd_lock)
            .with_issue_lock(self.state.issue_lock);

        let mut bytes = Vec::new();
        bytes.extend_from_slice(&flit0.into_bits().to_le_bytes());
        bytes.extend_from_slice(&flit1.into_bits().to_le_bytes());
        bytes
    }
}

#[derive(Debug, serde::Serialize, serde::Deserialize)]
pub struct IscTraceStream(Vec<IscTrace>);

impl IscTraceStream {
    pub fn from_bytes(bytes: &[u8]) -> Result<Self, TraceParsingError> {
        let mut trace_vec = Vec::new();

        for chunk in bytes.chunks(IscTrace::bytes_size()) {
            match IscTrace::from_bytes(chunk) {
                Ok(value) => {
                    tracing::debug!("Decoded {value:x?}");
                    trace_vec.push(value);
                }
                Err(e) => match e {
                    TraceParsingError::EmptyStream => {
                        break;
                    }
                    TraceParsingError::IncorrectValue(msg) => {
                        println!("Early Abort: Trace parsing encountered following error: {msg}");
                        println!("This event could occurred when the trace end is reached");
                        break;
                    }
                },
            }
        }
        Ok(IscTraceStream(trace_vec))
    }
}

